CREATE OR REPLACE FUNCTION public.atualizar_config_fideliza(p_ano integer, p_campo character varying, p_valor text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  EXECUTE format(
    'UPDATE programa_fideliza_config SET %I = $1, updated_at = NOW() WHERE ano = $2',
    p_campo
  ) USING p_valor, p_ano;

  RETURN jsonb_build_object('success', true);
END;
$function$

CREATE OR REPLACE FUNCTION public.calcular_reajuste_renovacao()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    IF NEW.valor_parcela_anterior IS NOT NULL AND NEW.valor_parcela_anterior > 0 THEN
        NEW.percentual_reajuste := ROUND(
            ((NEW.valor_parcela_novo - NEW.valor_parcela_anterior) / NEW.valor_parcela_anterior) * 100, 
            2
        );
    ELSE
        NEW.percentual_reajuste := 0;
    END IF;
    RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.deletar_penalidade_fideliza(p_id integer)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  DELETE FROM programa_fideliza_penalidades WHERE id = p_id;
  RETURN jsonb_build_object('success', true);
END;
$function$

CREATE OR REPLACE FUNCTION public.pode_enviar_pesquisa_evasao(p_evasao_id integer)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_data_evasao DATE;
  v_dias_desde_evasao INTEGER;
BEGIN
  SELECT data INTO v_data_evasao
  FROM movimentacoes_admin
  WHERE id = p_evasao_id;

  IF v_data_evasao IS NULL THEN
    RETURN FALSE;
  END IF;

  v_dias_desde_evasao := CURRENT_DATE - v_data_evasao;
  RETURN v_dias_desde_evasao >= 3;
END;
$function$

CREATE OR REPLACE FUNCTION public.registrar_penalidade_fideliza(p_ano integer, p_trimestre integer, p_unidade_id uuid, p_tipo character varying, p_descricao text, p_pontos integer, p_data_ocorrencia date, p_registrado_por character varying)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_id INTEGER;
BEGIN
  INSERT INTO programa_fideliza_penalidades (
    ano, trimestre, unidade_id, tipo, descricao, pontos_descontados, data_ocorrencia, registrado_por
  ) VALUES (
    p_ano, p_trimestre, p_unidade_id, p_tipo, p_descricao, p_pontos, p_data_ocorrencia, p_registrado_por
  )
  RETURNING id INTO v_id;

  RETURN jsonb_build_object('success', true, 'id', v_id);
END;
$function$

CREATE OR REPLACE FUNCTION public.sync_evasao_to_dados_mensais()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_ano INT; v_mes INT; v_unidade UUID; v_count INT; v_pagantes INT;
BEGIN
  IF TG_OP = 'DELETE' THEN
    IF OLD.tipo NOT IN ('evasao', 'nao_renovacao', 'aviso_previo') THEN RETURN OLD; END IF;
    v_ano := EXTRACT(YEAR FROM OLD.data); v_mes := EXTRACT(MONTH FROM OLD.data); v_unidade := OLD.unidade_id;
  ELSE
    IF NEW.tipo NOT IN ('evasao', 'nao_renovacao', 'aviso_previo') THEN RETURN NEW; END IF;
    v_ano := EXTRACT(YEAR FROM NEW.data); v_mes := EXTRACT(MONTH FROM NEW.data); v_unidade := NEW.unidade_id;
  END IF;

  SELECT COUNT(*) INTO v_count FROM movimentacoes_admin
  WHERE unidade_id = v_unidade AND tipo IN ('evasao', 'nao_renovacao')
    AND EXTRACT(YEAR FROM data) = v_ano AND EXTRACT(MONTH FROM data) = v_mes;

  SELECT alunos_pagantes INTO v_pagantes FROM dados_mensais
  WHERE unidade_id = v_unidade
    AND ((ano = v_ano AND mes = v_mes - 1) OR (ano = v_ano - 1 AND mes = 12 AND v_mes = 1))
  LIMIT 1;

  UPDATE dados_mensais
  SET evasoes = v_count,
      churn_rate = CASE WHEN COALESCE(v_pagantes, 0) > 0 THEN ROUND((v_count::NUMERIC / v_pagantes) * 100, 2) ELSE 0 END,
      updated_at = NOW()
  WHERE unidade_id = v_unidade AND ano = v_ano AND mes = v_mes;

  RETURN COALESCE(NEW, OLD);
END;
$function$
